// ─── AUTH CONTEXT ─────────────────────────────────────────────────────────────
const AuthContext = createContext(null);
const useAuth = () => useContext(AuthContext);
function AuthProvider({ children }) {
  const [user, setUser] = useState(() => { try { const s = localStorage.getItem("resume_user"); return s ? JSON.parse(s) : null; } catch { return null; } });
  const login = (u) => { setUser(u); localStorage.setItem("resume_user", JSON.stringify(u)); };
  const logout = () => { setUser(null); localStorage.removeItem("resume_user"); };
  return <AuthContext.Provider value={{ user, login, logout }}>{children}</AuthContext.Provider>;
}

// ─── RESUME CONTEXT ───────────────────────────────────────────────────────────
const ResumeContext = createContext(null);
const useResume = () => useContext(ResumeContext);
const defaultResume = {
  id: null, template: "modern",
  personal: { name: "", email: "", phone: "", location: "", github: "", linkedin: "", portfolio: "" },
  objective: "", skills: { languages: [], frameworks: [], tools: [], databases: [], cloud: [], soft: [] },
  projects: [], internships: [], certifications: [], education: [], achievements: [],
};
function ResumeProvider({ children }) {
  const [resume, setResume] = useState(defaultResume);
  const [savedResumes, setSavedResumes] = useState(() => { try { const s = localStorage.getItem("saved_resumes"); return s ? JSON.parse(s) : []; } catch { return []; } });
  const updateSection = (section, data) => setResume(r => ({ ...r, [section]: data }));
  const updatePersonal = (field, val) => setResume(r => ({ ...r, personal: { ...r.personal, [field]: val } }));
  const saveResume = () => {
    const id = resume.id || Date.now().toString();
    const updated = { ...resume, id, savedAt: new Date().toISOString() };
    setResume(updated);
    const list = savedResumes.filter(r => r.id !== id);
    const newList = [updated, ...list];
    setSavedResumes(newList);
    localStorage.setItem("saved_resumes", JSON.stringify(newList));
    return id;
  };
  const loadResume = (id) => { const f = savedResumes.find(r => r.id === id); if (f) setResume(f); };
  const newResume = () => setResume(defaultResume);
  return (
    <ResumeContext.Provider value={{ resume, setResume, updateSection, updatePersonal, saveResume, loadResume, newResume, savedResumes }}>
      {children}
    </ResumeContext.Provider>
  );
}

// ─── AI ───────────────────────────────────────────────────────────────────────
const API = "https://resume-ai-rwpt.onrender.com";

async function callAI(prompt, sys = "") {
  const token = JSON.parse(localStorage.getItem("resume_user") || "{}")?.token;
  const r = await fetch(`${API}/api/ai/improve`, {
    method: "POST",
    headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
    body: JSON.stringify({ text: prompt, type: "bullet", context: sys }),
  });
  const d = await r.json();
  if (d.error) throw new Error(d.error);
  return d.improved || "";
}

