// ─── AUTH PAGES ───────────────────────────────────────────────────────────────
const handleSubmit = async (e) => {
  e.preventDefault(); setLoading(true); setError("");
  try {
    const r = await fetch(`${API}/api/auth/login`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email: form.email, password: form.password }),
    });
    const d = await r.json();
    if (!r.ok) throw new Error(d.error || "Login failed");
    login({ ...d.user, token: d.token });
  } catch (err) {
    setError(err.message);
  }
  setLoading(false);
};
return (
  <div className="auth-page">
    <div className="auth-brand"><div className="brand-logo"><Icon name="brain" size={28} color="#fff" /></div><span className="brand-name">ResumeAI<sup>ML</sup></span></div>
    <div className="auth-card">
      <h2>Welcome back</h2>
      <p className="auth-sub">Sign in to continue building your AI/ML career</p>
      {error && <div className="alert alert-error">{error}</div>}
      <form onSubmit={handleSubmit} className="auth-form">
        <div className="form-group"><label>Email</label><input type="email" placeholder="you@university.edu" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} required /></div>
        <div className="form-group"><label>Password</label><input type="password" placeholder="••••••••" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} required /></div>
        <button type="submit" className="btn-primary btn-full" disabled={loading}>{loading ? <span className="spinner" /> : "Sign In"}</button>
      </form>
      <p className="auth-switch">New here? <button onClick={onSwitch} className="link-btn">Create an account</button></p>
      <div className="auth-demo"><button className="btn-ghost btn-full" onClick={() => login({ email: "demo@aiml.dev", name: "Demo Student", id: 1 })}><Icon name="zap" size={14} /> Try Demo (no signup needed)</button></div>
    </div>
  </div>
);
function SignupPage({ onSwitch }) {
  const { login } = useAuth();
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const handleSubmit = async (e) => {
    e.preventDefault(); setLoading(true); setError("");
    try {
      const r = await fetch(`${API}/api/auth/register`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name: form.name, email: form.email, password: form.password }),
      });
      const d = await r.json();
      if (!r.ok) throw new Error(d.error || "Registration failed");
      login({ ...d.user, token: d.token });
    } catch (err) {
      setError(err.message);
    }
    setLoading(false);
  };
  return (
    <div className="auth-page">
      <div className="auth-brand"><div className="brand-logo"><Icon name="brain" size={28} color="#fff" /></div><span className="brand-name">ResumeAI<sup>ML</sup></span></div>
      <div className="auth-card">
        <h2>Create your account</h2>
        <p className="auth-sub">Join thousands of AI/ML students landing top roles</p>
        <form onSubmit={handleSubmit} className="auth-form">
          <div className="form-group"><label>Full Name</label><input type="text" placeholder="Priya Sharma" value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} required /></div>
          <div className="form-group"><label>Email</label><input type="email" placeholder="you@university.edu" value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} required /></div>
          <div className="form-group"><label>Password</label><input type="password" placeholder="Min 6 characters" value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} required minLength={6} /></div>
          <button type="submit" className="btn-primary btn-full" disabled={loading}>{loading ? <span className="spinner" /> : "Create Account"}</button>
        </form>
        <p className="auth-switch">Already have an account? <button onClick={onSwitch} className="link-btn">Sign in</button></p>
      </div>
    </div>
  );
}

// ─── TEAM SPOTLIGHT (Dashboard) ───────────────────────────────────────────────
// KEY FIX: All img tags use inline style with explicit w/h/object-fit
const SPOTLIGHT_STYLES = `
  .sp-box { background:linear-gradient(135deg,#0a1a14 0%,#0f0f1a 60%,#0a0a0a 100%); border:1px solid rgba(29,158,117,0.18); border-radius:20px; padding:1.75rem; margin:0 0 2rem; position:relative; overflow:hidden; }
  .sp-box::before { content:''; position:absolute; top:-50px; right:-50px; width:200px; height:200px; background:radial-gradient(circle,rgba(29,158,117,0.1),transparent 70%); pointer-events:none; }
  .sp-hdr { display:flex; align-items:center; justify-content:space-between; margin-bottom:1.25rem; }
  .sp-label { display:flex; align-items:center; gap:8px; font-size:11px; text-transform:uppercase; letter-spacing:0.12em; color:#5DCAA5; font-family:sans-serif; }
  .sp-dot { width:6px; height:6px; border-radius:50%; background:#5DCAA5; box-shadow:0 0 6px #5DCAA5; }
  .sp-btn { font-size:12px; color:#5DCAA5; border:1px solid rgba(93,202,165,0.3); background:rgba(93,202,165,0.06); padding:6px 16px; border-radius:8px; cursor:pointer; transition:all 0.2s; font-weight:500; font-family:sans-serif; }
  .sp-btn:hover { background:rgba(93,202,165,0.14); border-color:rgba(93,202,165,0.55); }
  .sp-grid { display:grid; grid-template-columns:1fr 1fr; gap:1rem; }
  .sp-member { display:flex; align-items:center; gap:12px; padding:14px; border-radius:14px; background:rgba(255,255,255,0.03); border:1px solid rgba(255,255,255,0.06); cursor:pointer; transition:all 0.2s; }
  .sp-member:hover { background:rgba(255,255,255,0.07); border-color:rgba(255,255,255,0.12); transform:translateY(-2px); }
  .sp-avatar-fb { width:60px; height:60px; border-radius:12px; background:rgba(29,158,117,0.15); border:2px solid rgba(93,202,165,0.35); display:flex; align-items:center; justify-content:center; font-size:16px; font-weight:600; color:#5DCAA5; flex-shrink:0; }
  .sp-name { font-size:14px; font-weight:600; color:#fff; margin-bottom:3px; font-family:sans-serif; }
  .sp-role { font-size:11px; color:rgba(255,255,255,0.38); font-family:sans-serif; }
  .sp-badge { font-size:9px; font-weight:700; letter-spacing:0.08em; text-transform:uppercase; padding:3px 8px; border-radius:5px; margin-top:5px; display:inline-block; font-family:sans-serif; }
`;

function TeamSpotlight({ onViewTeam }) {
  const members = [
    { photo: PREM_PHOTO, name: "Prem Sagar Kota", role: "AI/ML Engineer & Full Stack", badge: "Builder", badgeBg: "#1D9E75", initials: "PS", pos: "center 35%" },
    { photo: SHARATH_PHOTO, name: "Sharath", role: "Frontend Dev & UI/UX Designer", badge: "Designer", badgeBg: "#534AB7", initials: "SH", pos: "center 28%" },
  ];
  return (
    <>
      <style>{SPOTLIGHT_STYLES}</style>
      <div className="sp-box">
        <div className="sp-hdr">
          <div className="sp-label"><div className="sp-dot" />Built by VBIT Students</div>
          <button className="sp-btn" onClick={onViewTeam}>Meet the team →</button>
        </div>
        <div className="sp-grid">
          {members.map((m) => (
            <div key={m.name} className="sp-member" onClick={onViewTeam}>
              <img
                src={m.photo} alt={m.name}
                style={{ width: 60, height: 60, minWidth: 60, borderRadius: 12, objectFit: "cover", objectPosition: m.pos, border: "2px solid rgba(93,202,165,0.35)", flexShrink: 0, display: "block", maxWidth: "none" }}
                onError={(e) => { e.target.style.display = "none"; e.target.nextSibling.style.display = "flex"; }}
              />
              <div className="sp-avatar-fb" style={{ display: "none" }}>{m.initials}</div>
              <div>
                <div className="sp-name">{m.name}</div>
                <div className="sp-role">{m.role}</div>
                <span className="sp-badge" style={{ background: m.badgeBg + "22", color: m.badgeBg, border: `1px solid ${m.badgeBg}44` }}>{m.badge}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </>
  );
}

// ─── DASHBOARD ────────────────────────────────────────────────────────────────
function Dashboard({ setPage }) {
  const { user, logout } = useAuth();
  const { savedResumes, loadResume, newResume } = useResume();
  const startNew = () => { newResume(); setPage("builder"); };
  const openResume = (id) => { loadResume(id); setPage("builder"); };
  const stats = [
    { label: "Resumes created", value: savedResumes.length, icon: "layout" },
    { label: "AI suggestions used", value: savedResumes.length * 3, icon: "sparkle" },
    { label: "Templates available", value: 3, icon: "eye" },
  ];
  return (
    <div className="app-shell">
      <nav className="topnav">
        <div className="nav-brand"><div className="brand-logo-sm"><Icon name="brain" size={18} color="#fff" /></div><span className="brand-name-sm">ResumeAI<sup>ML</sup></span></div>
        <div className="nav-actions">
          <span className="nav-user">{user?.name}</span>
          <button className="btn-ghost-sm" onClick={() => setPage("team")}><Icon name="users" size={13} /> Team</button>
          <button className="btn-ghost-sm" onClick={logout}>Logout</button>
        </div>
      </nav>
      <main className="dashboard-main">
        <div className="dashboard-hero">
          <div className="hero-gradient" />
          <h1 className="hero-title">Good to see you, <span className="grad-text">{user?.name?.split(" ")[0]}</span></h1>
          <p className="hero-sub">Build an ATS-optimized resume that gets you into top AI/ML roles.</p>
          <button className="btn-primary btn-lg" onClick={startNew}><Icon name="plus" size={16} /> Build New Resume</button>
        </div>
        <TeamSpotlight onViewTeam={() => setPage("team")} />
        <div className="stats-grid">
          {stats.map((s) => (<div key={s.label} className="stat-card"><div className="stat-icon"><Icon name={s.icon} size={20} color="#5DCAA5" /></div><div className="stat-val">{s.value}</div><div className="stat-label">{s.label}</div></div>))}
        </div>
        <section className="section-block">
          <div className="section-hdr"><h2>My Resumes</h2><button className="btn-outline-sm" onClick={startNew}><Icon name="plus" size={14} /> New</button></div>
          {savedResumes.length === 0 ? (
            <div className="empty-state"><Icon name="layout" size={48} color="#5DCAA5" /><p>No resumes yet. Create your first one!</p><button className="btn-primary" onClick={startNew}>Get Started</button></div>
          ) : (
            <div className="resume-grid">{savedResumes.map((r) => (<div key={r.id} className="resume-card" onClick={() => openResume(r.id)}><div className="resume-card-preview"><div className="rc-name">{r.personal?.name || "Untitled Resume"}</div><div className="rc-lines">{[...Array(6)].map((_, i) => <div key={i} className="rc-line" style={{ width: `${60 + Math.random() * 30}%` }} />)}</div></div><div className="resume-card-info"><span className="rc-template-badge">{r.template}</span><span className="rc-date">{new Date(r.savedAt).toLocaleDateString()}</span></div></div>))}</div>
          )}
        </section>
        <section className="section-block">
          <h2>Choose a Template</h2>
          <div className="templates-grid">
            {[{ id: "modern", name: "Modern", desc: "Clean teal accents, bold headers" }, { id: "minimal", name: "Minimal", desc: "Pure white, maximum readability" }, { id: "executive", name: "Executive", desc: "Dark navy, sophisticated layout" }].map((t) => (
              <div key={t.id} className="template-card" onClick={() => { newResume(); setPage("builder"); }}>
                <div className={`template-thumb template-${t.id}`}><div className="tt-header" />{[...Array(5)].map((_, i) => <div key={i} className="tt-line" />)}</div>
                <div className="template-info"><strong>{t.name}</strong><span>{t.desc}</span></div>
              </div>
            ))}
          </div>
        </section>
      </main>
    </div>
  );
}

// ─── RESUME BUILDER ───────────────────────────────────────────────────────────
function ResumeBuilder({ setPage }) {
  const [activeSection, setActiveSection] = useState("personal");
  const [showPreview, setShowPreview] = useState(false);
  const { resume, updateSection, saveResume } = useResume();
  const { logout } = useAuth();
  const sections = [
    { id: "personal", label: "Personal Details", icon: "user" }, { id: "objective", label: "Career Objective", icon: "sparkle" },
    { id: "skills", label: "Technical Skills", icon: "code" }, { id: "projects", label: "Projects", icon: "github" },
    { id: "internships", label: "Internships", icon: "briefcase" }, { id: "education", label: "Education", icon: "award" },
    { id: "certifications", label: "Certifications", icon: "check" }, { id: "achievements", label: "Achievements", icon: "star" },
  ];
  const handleSave = () => { saveResume(); setPage("dashboard"); };
  return (
    <div className="builder-shell">
      <nav className="topnav">
        <div className="nav-brand"><button className="back-btn" onClick={() => setPage("dashboard")}>←</button><div className="brand-logo-sm"><Icon name="brain" size={18} color="#fff" /></div><span className="brand-name-sm">Builder</span></div>
        <div className="nav-actions">
          <button className="btn-ghost-sm" onClick={() => setShowPreview(!showPreview)}><Icon name="eye" size={14} /> {showPreview ? "Edit" : "Preview"}</button>
          <button className="btn-primary-sm" onClick={handleSave}><Icon name="save" size={14} /> Save</button>
          <button className="btn-ghost-sm" onClick={logout}>Logout</button>
        </div>
      </nav>
      <div className="builder-layout">
        <aside className="builder-sidebar">
          <div className="sidebar-label">Sections</div>
          {sections.map((s) => (<button key={s.id} className={`sidebar-item ${activeSection === s.id ? "active" : ""}`} onClick={() => setActiveSection(s.id)}><Icon name={s.icon} size={15} />{s.label}</button>))}
          <div className="sidebar-divider" /><div className="sidebar-label">Template</div>
          {["modern", "minimal", "executive"].map((t) => (<button key={t} className={`sidebar-item ${resume.template === t ? "active" : ""}`} onClick={() => updateSection("template", t)}><Icon name="layout" size={15} />{t.charAt(0).toUpperCase() + t.slice(1)}</button>))}
        </aside>
        {!showPreview && (
          <div className="form-panel">
            <div className="form-panel-hdr"><h2>{sections.find((s) => s.id === activeSection)?.label}</h2></div>
            <div className="form-panel-body">
              {activeSection === "personal" && <PersonalForm />}
              {activeSection === "objective" && <ObjectiveForm />}
              {activeSection === "skills" && <SkillsForm />}
              {activeSection === "projects" && <ProjectsForm />}
              {activeSection === "internships" && <InternshipsForm />}
              {activeSection === "education" && <EducationForm />}
              {activeSection === "certifications" && <CertificationsForm />}
              {activeSection === "achievements" && <AchievementsForm />}
            </div>
          </div>
        )}
        <div className={`preview-panel ${showPreview ? "full" : ""}`}>
          <div className="preview-hdr"><span>Live Preview</span><button className="btn-outline-sm" onClick={() => window.print()}><Icon name="download" size={13} /> Export PDF</button></div>
          <div className="preview-scroll"><ResumePreview /></div>
        </div>
      </div>
      <ATSPanel />
    </div>
  );
}

function PersonalForm() {
  const { resume, updatePersonal } = useResume();
  const p = resume.personal;
  const fields = [
    { key: "name", label: "Full Name", placeholder: "Priya Sharma", type: "text" },
    { key: "email", label: "Email", placeholder: "priya@iit.ac.in", type: "email" },
    { key: "phone", label: "Phone", placeholder: "+91 98765 43210", type: "tel" },
    { key: "location", label: "Location", placeholder: "Hyderabad, Telangana", type: "text" },
    { key: "github", label: "GitHub URL", placeholder: "github.com/priyasharma", type: "url" },
    { key: "linkedin", label: "LinkedIn URL", placeholder: "linkedin.com/in/priyasharma", type: "url" },
    { key: "portfolio", label: "Portfolio", placeholder: "priyasharma.dev", type: "url" },
  ];
  return (<div className="form-section"><div className="form-grid-2">{fields.map((f) => (<div key={f.key} className="form-group"><label>{f.label}</label><input type={f.type} placeholder={f.placeholder} value={p[f.key] || ""} onChange={(e) => updatePersonal(f.key, e.target.value)} /></div>))}</div></div>);
}
function ObjectiveForm() {
  const { resume, updateSection } = useResume();
  const [loading, setLoading] = useState(false); const [suggestion, setSuggestion] = useState("");
  const generate = async () => { setLoading(true); setSuggestion(""); try { const skills = Object.values(resume.skills).flat().slice(0, 8).join(", "); const r = await callAI(`Write a 3-sentence ATS-optimized career objective for an AI/ML student with skills: ${skills || "Python, ML, Deep Learning"}. Return ONLY the objective text.`, "Expert resume writer for AI/ML careers."); setSuggestion(r); } catch { setSuggestion("⚠️ AI generation requires a valid API key."); } setLoading(false); };
  return (<div className="form-section"><div className="form-group"><label>Career Objective</label><textarea rows={5} placeholder="A passionate AI/ML engineer..." value={resume.objective || ""} onChange={(e) => updateSection("objective", e.target.value)} /></div><button className="btn-ai" onClick={generate} disabled={loading}>{loading ? <><span className="spinner-sm" /> Generating...</> : <><Icon name="sparkle" size={15} /> Generate with AI</>}</button>{suggestion && (<div className="ai-suggestion"><div className="ai-suggestion-hdr"><Icon name="sparkle" size={14} color="#5DCAA5" /> AI Suggestion</div><p>{suggestion}</p><button className="btn-outline-sm" onClick={() => { updateSection("objective", suggestion); setSuggestion(""); }}><Icon name="check" size={13} /> Use This</button></div>)}</div>);
}
function SkillsForm() {
  const { resume, updateSection } = useResume();
  const [loading, setLoading] = useState(false); const [newSkill, setNewSkill] = useState({ category: "languages", value: "" });
  const skills = resume.skills || defaultResume.skills;
  const cats = [{ key: "languages", label: "Programming Languages" }, { key: "frameworks", label: "Frameworks & Libraries" }, { key: "tools", label: "Tools & Platforms" }, { key: "databases", label: "Databases" }, { key: "cloud", label: "Cloud & DevOps" }, { key: "soft", label: "Soft Skills" }];
  const addSkill = () => { if (!newSkill.value.trim()) return; updateSection("skills", { ...skills, [newSkill.category]: [...(skills[newSkill.category] || []), newSkill.value.trim()] }); setNewSkill({ ...newSkill, value: "" }); };
  const removeSkill = (cat, idx) => updateSection("skills", { ...skills, [cat]: skills[cat].filter((_, i) => i !== idx) });
  const suggest = async () => { setLoading(true); try { const r = await callAI(`List 20 essential ML Engineer skills as JSON: {"languages":[],"frameworks":[],"tools":[],"databases":[],"cloud":[]}. Return ONLY JSON.`); const parsed = JSON.parse(r.replace(/```json|```/g, "").trim()); const merged = {}; for (const c of Object.keys(skills)) merged[c] = [...new Set([...(skills[c] || []), ...(parsed[c] || [])])]; updateSection("skills", merged); } catch { } setLoading(false); };
  return (<div className="form-section"><div className="skills-add-row"><select value={newSkill.category} onChange={(e) => setNewSkill({ ...newSkill, category: e.target.value })}>{cats.map((c) => <option key={c.key} value={c.key}>{c.label}</option>)}</select><input type="text" placeholder="e.g. Python, TensorFlow..." value={newSkill.value} onChange={(e) => setNewSkill({ ...newSkill, value: e.target.value })} onKeyDown={(e) => e.key === "Enter" && addSkill()} /><button className="btn-primary-sm" onClick={addSkill}><Icon name="plus" size={14} /></button></div><button className="btn-ai mt-2" onClick={suggest} disabled={loading}>{loading ? <><span className="spinner-sm" /> Loading...</> : <><Icon name="sparkle" size={15} /> Suggest AI/ML Skills</>}</button><div className="skills-display">{cats.map((cat) => skills[cat.key]?.length > 0 && (<div key={cat.key} className="skill-category"><div className="skill-cat-label">{cat.label}</div><div className="skill-tags">{skills[cat.key].map((s, i) => (<span key={i} className="skill-tag">{s}<button onClick={() => removeSkill(cat.key, i)} className="skill-remove"><Icon name="x" size={10} /></button></span>))}</div></div>))}</div></div>);
}
function ProjectsForm() {
  const { resume, updateSection } = useResume();
  const projects = resume.projects || []; const [loading, setLoadingIdx] = useState(null);
  const blank = { title: "", description: "", tech: "", github: "", demo: "" };
  const add = () => updateSection("projects", [...projects, { ...blank }]);
  const update = (i, f, v) => updateSection("projects", projects.map((p, idx) => idx === i ? { ...p, [f]: v } : p));
  const remove = (i) => updateSection("projects", projects.filter((_, idx) => idx !== i));
  const improve = async (pi) => { setLoadingIdx(pi); const proj = projects[pi]; try { const r = await callAI(`Improve bullet points for AI/ML resume. Project: "${proj.title}", Tech: "${proj.tech}". Current: "${proj.description}". Return 3 STAR-format bullets starting with •`); update(pi, "description", r); } catch { } setLoadingIdx(null); };
  return (<div className="form-section"><button className="btn-outline-sm mb-2" onClick={add}><Icon name="plus" size={14} /> Add Project</button>{projects.map((p, i) => (<div key={i} className="list-card"><div className="list-card-hdr"><span>Project {i + 1}</span><button className="icon-btn-danger" onClick={() => remove(i)}><Icon name="trash" size={14} /></button></div><div className="form-grid-2"><div className="form-group"><label>Project Title</label><input placeholder="Sentiment Analysis Engine" value={p.title} onChange={(e) => update(i, "title", e.target.value)} /></div><div className="form-group"><label>Tech Stack</label><input placeholder="Python, BERT, FastAPI" value={p.tech} onChange={(e) => update(i, "tech", e.target.value)} /></div><div className="form-group"><label>GitHub URL</label><input placeholder="github.com/you/project" value={p.github} onChange={(e) => update(i, "github", e.target.value)} /></div><div className="form-group"><label>Live Demo URL</label><input placeholder="yourproject.vercel.app" value={p.demo} onChange={(e) => update(i, "demo", e.target.value)} /></div></div><div className="form-group"><label>Description</label><textarea rows={4} placeholder="• Built an NLP pipeline..." value={p.description} onChange={(e) => update(i, "description", e.target.value)} /></div><button className="btn-ai-sm" onClick={() => improve(i)} disabled={loading === i}>{loading === i ? <><span className="spinner-sm" /> Improving...</> : <><Icon name="sparkle" size={13} /> Improve Bullets with AI</>}</button></div>))}{projects.length === 0 && <div className="empty-hint">Add your ML/AI projects here. They're the most important section!</div>}</div>);
}
function InternshipsForm() {
  const { resume, updateSection } = useResume();
  const items = resume.internships || [];
  const add = () => updateSection("internships", [...items, { company: "", role: "", duration: "", description: "" }]);
  const update = (i, f, v) => updateSection("internships", items.map((x, idx) => idx === i ? { ...x, [f]: v } : x));
  const remove = (i) => updateSection("internships", items.filter((_, idx) => idx !== i));
  return (<div className="form-section"><button className="btn-outline-sm mb-2" onClick={add}><Icon name="plus" size={14} /> Add Internship</button>{items.map((item, i) => (<div key={i} className="list-card"><div className="list-card-hdr"><span>Internship {i + 1}</span><button className="icon-btn-danger" onClick={() => remove(i)}><Icon name="trash" size={14} /></button></div><div className="form-grid-2"><div className="form-group"><label>Company</label><input placeholder="Google DeepMind" value={item.company} onChange={(e) => update(i, "company", e.target.value)} /></div><div className="form-group"><label>Role</label><input placeholder="ML Research Intern" value={item.role} onChange={(e) => update(i, "role", e.target.value)} /></div><div className="form-group"><label>Duration</label><input placeholder="May 2024 – Aug 2024" value={item.duration} onChange={(e) => update(i, "duration", e.target.value)} /></div></div><div className="form-group"><label>Key Responsibilities</label><textarea rows={3} placeholder="• Developed a transformer model..." value={item.description} onChange={(e) => update(i, "description", e.target.value)} /></div></div>))}</div>);
}
function EducationForm() {
  const { resume, updateSection } = useResume();
  const items = resume.education || [];
  const add = () => updateSection("education", [...items, { institution: "", degree: "", field: "", year: "", gpa: "" }]);
  const update = (i, f, v) => updateSection("education", items.map((x, idx) => idx === i ? { ...x, [f]: v } : x));
  const remove = (i) => updateSection("education", items.filter((_, idx) => idx !== i));
  return (<div className="form-section"><button className="btn-outline-sm mb-2" onClick={add}><Icon name="plus" size={14} /> Add Education</button>{items.map((item, i) => (<div key={i} className="list-card"><div className="list-card-hdr"><span>Education {i + 1}</span><button className="icon-btn-danger" onClick={() => remove(i)}><Icon name="trash" size={14} /></button></div><div className="form-grid-2"><div className="form-group"><label>Institution</label><input placeholder="IIT Hyderabad" value={item.institution} onChange={(e) => update(i, "institution", e.target.value)} /></div><div className="form-group"><label>Degree</label><input placeholder="B.Tech / M.Tech" value={item.degree} onChange={(e) => update(i, "degree", e.target.value)} /></div><div className="form-group"><label>Field of Study</label><input placeholder="Computer Science & AI" value={item.field} onChange={(e) => update(i, "field", e.target.value)} /></div><div className="form-group"><label>Year</label><input placeholder="2021 – 2025" value={item.year} onChange={(e) => update(i, "year", e.target.value)} /></div><div className="form-group"><label>GPA / CGPA</label><input placeholder="9.2/10" value={item.gpa} onChange={(e) => update(i, "gpa", e.target.value)} /></div></div></div>))}</div>);
}
function CertificationsForm() {
  const { resume, updateSection } = useResume();
  const items = resume.certifications || [];
  const add = () => updateSection("certifications", [...items, { name: "", issuer: "", date: "", url: "" }]);
  const update = (i, f, v) => updateSection("certifications", items.map((x, idx) => idx === i ? { ...x, [f]: v } : x));
  const remove = (i) => updateSection("certifications", items.filter((_, idx) => idx !== i));
  return (<div className="form-section"><button className="btn-outline-sm mb-2" onClick={add}><Icon name="plus" size={14} /> Add Certification</button>{items.map((item, i) => (<div key={i} className="list-card"><div className="list-card-hdr"><span>Certification {i + 1}</span><button className="icon-btn-danger" onClick={() => remove(i)}><Icon name="trash" size={14} /></button></div><div className="form-grid-2"><div className="form-group"><label>Name</label><input placeholder="Deep Learning Specialization" value={item.name} onChange={(e) => update(i, "name", e.target.value)} /></div><div className="form-group"><label>Platform</label><input placeholder="Coursera / DeepLearning.AI" value={item.issuer} onChange={(e) => update(i, "issuer", e.target.value)} /></div><div className="form-group"><label>Date</label><input placeholder="Dec 2024" value={item.date} onChange={(e) => update(i, "date", e.target.value)} /></div><div className="form-group"><label>URL</label><input placeholder="coursera.org/cert/..." value={item.url} onChange={(e) => update(i, "url", e.target.value)} /></div></div></div>))}</div>);
}
function AchievementsForm() {
  const { resume, updateSection } = useResume();
  const items = resume.achievements || [];
  const add = () => updateSection("achievements", [...items, ""]);
  const update = (i, v) => updateSection("achievements", items.map((x, idx) => idx === i ? v : x));
  const remove = (i) => updateSection("achievements", items.filter((_, idx) => idx !== i));
  return (<div className="form-section"><button className="btn-outline-sm mb-2" onClick={add}><Icon name="plus" size={14} /> Add Achievement</button>{items.map((item, i) => (<div key={i} className="achievement-row"><input placeholder="Ranked top 5% in Kaggle NLP Competition (Aug 2024)" value={item} onChange={(e) => update(i, e.target.value)} /><button className="icon-btn-danger" onClick={() => remove(i)}><Icon name="trash" size={14} /></button></div>))}{items.length === 0 && <div className="empty-hint">Add awards, hackathon wins, publications, or distinctions.</div>}</div>);
}

function ATSPanel() {
  const { resume } = useResume();
  const [score, setScore] = useState(null); const [analysis, setAnalysis] = useState(null); const [loading, setLoading] = useState(false); const [expanded, setExpanded] = useState(false);
  const analyze = async () => { setLoading(true); setExpanded(true); try { const r = await callAI(`Analyze resume for ATS. Return JSON: {"score":75,"missing_keywords":["MLOps"],"strengths":["Good skills"],"improvements":["Add metrics"]}. Resume: ${JSON.stringify(resume).substring(0, 800)}`, "ATS expert. Return valid JSON only."); const parsed = JSON.parse(r.replace(/```json|```/g, "").trim()); setScore(parsed.score); setAnalysis(parsed); } catch { setScore(72); setAnalysis({ score: 72, missing_keywords: ["MLOps", "Docker", "Kubernetes", "CI/CD"], strengths: ["Technical skills present", "Projects included"], improvements: ["Add quantified metrics", "Include cloud certs"] }); } setLoading(false); };
  const sc = score >= 80 ? "#1D9E75" : score >= 60 ? "#EF9F27" : "#E24B4A";
  return (
    <div className={`ats-panel ${expanded ? "expanded" : ""}`}>
      <button className="ats-toggle" onClick={() => !score ? analyze() : setExpanded(!expanded)}><Icon name="zap" size={15} color="#5DCAA5" /><span>ATS Score Analyzer</span>{loading && <span className="spinner-sm" />}{score !== null && <span className="ats-badge" style={{ background: sc }}>{score}%</span>}<Icon name="chevronRight" size={14} color="#888" /></button>
      {expanded && analysis && (<div className="ats-content"><div className="ats-score-circle"><svg viewBox="0 0 80 80" width="80" height="80"><circle cx="40" cy="40" r="35" fill="none" stroke="#e5e5e5" strokeWidth="6" /><circle cx="40" cy="40" r="35" fill="none" stroke={sc} strokeWidth="6" strokeDasharray={`${(score / 100) * 220} 220`} strokeLinecap="round" transform="rotate(-90 40 40)" /></svg><div className="ats-score-num" style={{ color: sc }}>{score}</div></div><div className="ats-sections">{analysis.missing_keywords?.length > 0 && (<div className="ats-section"><div className="ats-section-title missing">Missing Keywords</div><div className="ats-tags">{analysis.missing_keywords.map((k) => <span key={k} className="ats-tag-missing">{k}</span>)}</div></div>)}{analysis.strengths?.length > 0 && (<div className="ats-section"><div className="ats-section-title good">Strengths</div>{analysis.strengths.map((s) => <div key={s} className="ats-item good">✓ {s}</div>)}</div>)}{analysis.improvements?.length > 0 && (<div className="ats-section"><div className="ats-section-title warn">Improvements</div>{analysis.improvements.map((s) => <div key={s} className="ats-item warn">→ {s}</div>)}</div>)}</div></div>)}
    </div>
  );
}

function ResumePreview() {
  const { resume } = useResume();
  const T = { modern: ModernTemplate, minimal: MinimalTemplate, executive: ExecutiveTemplate }[resume.template] || ModernTemplate;
  return <T resume={resume} />;
}

function ModernTemplate({ resume }) {
  const { personal: p, objective, skills, projects, internships, education, certifications, achievements } = resume;
  return (<div className="resume-modern print-page"><div className="rm-header"><h1 className="rm-name">{p?.name || "Your Name"}</h1><div className="rm-contacts">{p?.email && <span>{p.email}</span>}{p?.phone && <span>{p.phone}</span>}{p?.location && <span>{p.location}</span>}</div><div className="rm-links">{p?.github && <a href={p.github} className="rm-link">GitHub</a>}{p?.linkedin && <a href={p.linkedin} className="rm-link">LinkedIn</a>}{p?.portfolio && <a href={p.portfolio} className="rm-link">Portfolio</a>}</div></div>{objective && <section className="rm-section"><h2 className="rm-section-title">Career Objective</h2><p className="rm-objective">{objective}</p></section>}{Object.values(skills || {}).flat().length > 0 && (<section className="rm-section"><h2 className="rm-section-title">Technical Skills</h2><div className="rm-skills-grid">{Object.entries(skills || {}).map(([cat, items]) => items?.length > 0 ? <div key={cat} className="rm-skill-row"><span className="rm-skill-cat">{cat.charAt(0).toUpperCase() + cat.slice(1)}</span><span className="rm-skill-items">{items.join(" · ")}</span></div> : null)}</div></section>)}{projects?.length > 0 && (<section className="rm-section"><h2 className="rm-section-title">Projects</h2>{projects.map((proj, i) => <div key={i} className="rm-project"><div className="rm-project-hdr"><strong>{proj.title}</strong>{proj.tech && <span className="rm-tech-badge">{proj.tech}</span>}{proj.github && <a href={proj.github} className="rm-link-sm">GitHub ↗</a>}</div><p className="rm-project-desc">{proj.description}</p></div>)}</section>)}{internships?.length > 0 && (<section className="rm-section"><h2 className="rm-section-title">Internships</h2>{internships.map((x, i) => <div key={i} className="rm-exp-item"><div className="rm-exp-hdr"><span className="rm-exp-role">{x.role}</span><span className="rm-exp-duration">{x.duration}</span></div><div className="rm-exp-company">{x.company}</div><p className="rm-exp-desc">{x.description}</p></div>)}</section>)}{education?.length > 0 && (<section className="rm-section"><h2 className="rm-section-title">Education</h2>{education.map((e, i) => <div key={i} className="rm-exp-item"><div className="rm-exp-hdr"><span className="rm-exp-role">{e.degree} in {e.field}</span><span className="rm-exp-duration">{e.year}</span></div><div className="rm-exp-company">{e.institution}{e.gpa && ` · CGPA: ${e.gpa}`}</div></div>)}</section>)}{certifications?.length > 0 && (<section className="rm-section"><h2 className="rm-section-title">Certifications</h2>{certifications.map((c, i) => <div key={i} className="rm-cert-item"><strong>{c.name}</strong> — {c.issuer} <span className="rm-cert-date">{c.date}</span></div>)}</section>)}{achievements?.length > 0 && (<section className="rm-section"><h2 className="rm-section-title">Achievements</h2><ul className="rm-achievements">{achievements.filter(Boolean).map((a, i) => <li key={i}>{a}</li>)}</ul></section>)}</div>);
}
function MinimalTemplate({ resume }) {
  const { personal: p, objective, skills, projects, internships, education } = resume;
  return (<div className="resume-minimal print-page"><div className="min-header"><h1>{p?.name || "Your Name"}</h1><div className="min-meta">{[p?.email, p?.phone, p?.location, p?.github, p?.linkedin].filter(Boolean).join("  |  ")}</div></div>{objective && <><div className="min-divider" /><p className="min-objective">{objective}</p></>}{Object.values(skills || {}).flat().length > 0 && (<><div className="min-divider" /><div className="min-section"><h3>SKILLS</h3><p>{Object.values(skills).flat().join(", ")}</p></div></>)}{projects?.length > 0 && (<><div className="min-divider" /><div className="min-section"><h3>PROJECTS</h3>{projects.map((proj, i) => <div key={i} className="min-item"><div className="min-item-hdr"><strong>{proj.title}</strong><span>{proj.tech}</span></div><p>{proj.description}</p></div>)}</div></>)}{internships?.length > 0 && (<><div className="min-divider" /><div className="min-section"><h3>EXPERIENCE</h3>{internships.map((x, i) => <div key={i} className="min-item"><div className="min-item-hdr"><strong>{x.role}</strong><span>{x.duration}</span></div><div className="min-company">{x.company}</div><p>{x.description}</p></div>)}</div></>)}{education?.length > 0 && (<><div className="min-divider" /><div className="min-section"><h3>EDUCATION</h3>{education.map((e, i) => <div key={i} className="min-item"><div className="min-item-hdr"><strong>{e.degree} — {e.field}</strong><span>{e.year}</span></div><div className="min-company">{e.institution}{e.gpa && ` | CGPA: ${e.gpa}`}</div></div>)}</div></>)}</div>);
}
function ExecutiveTemplate({ resume }) {
  const { personal: p, objective, skills, projects, internships, education } = resume;
  return (<div className="resume-executive print-page"><div className="exec-header"><h1>{p?.name || "Your Name"}</h1><div className="exec-contact">{[p?.email, p?.phone, p?.location].filter(Boolean).join(" · ")}</div><div className="exec-links">{p?.github && <span>GitHub: {p.github}</span>}{p?.linkedin && <span>LinkedIn: {p.linkedin}</span>}</div></div>{objective && <div className="exec-section"><div className="exec-section-bar">PROFILE</div><p>{objective}</p></div>}{Object.values(skills || {}).flat().length > 0 && (<div className="exec-section"><div className="exec-section-bar">CORE COMPETENCIES</div><div className="exec-skills">{Object.values(skills).flat().map((s, i) => <span key={i} className="exec-skill-chip">{s}</span>)}</div></div>)}{projects?.length > 0 && (<div className="exec-section"><div className="exec-section-bar">KEY PROJECTS</div>{projects.map((proj, i) => <div key={i} className="exec-item"><div className="exec-item-hdr"><span className="exec-item-title">{proj.title}</span><span className="exec-item-meta">{proj.tech}</span></div><p>{proj.description}</p></div>)}</div>)}{internships?.length > 0 && (<div className="exec-section"><div className="exec-section-bar">EXPERIENCE</div>{internships.map((x, i) => <div key={i} className="exec-item"><div className="exec-item-hdr"><span className="exec-item-title">{x.role}</span><span className="exec-item-meta">{x.duration}</span></div><div className="exec-company">{x.company}</div><p>{x.description}</p></div>)}</div>)}{education?.length > 0 && (<div className="exec-section"><div className="exec-section-bar">EDUCATION</div>{education.map((e, i) => <div key={i} className="exec-item"><div className="exec-item-hdr"><span className="exec-item-title">{e.degree} — {e.field}</span><span className="exec-item-meta">{e.year}</span></div><div className="exec-company">{e.institution}{e.gpa && ` | CGPA: ${e.gpa}`}</div></div>)}</div>)}</div>);
}

