// ─── ROOT ─────────────────────────────────────────────────────────────────────
function AppInner() {
  const { user } = useAuth();
  const [page, setPage] = useState("auth");
  const [authMode, setAuthMode] = useState("login");
  useEffect(() => { if (user) setPage("dashboard"); else setPage("auth"); }, [user]);
  if (!user) return authMode === "login" ? <LoginPage onSwitch={() => setAuthMode("signup")} /> : <SignupPage onSwitch={() => setAuthMode("login")} />;
  if (page === "builder") return <ResumeBuilder setPage={setPage} />;
  if (page === "team") return <TeamPage setPage={setPage} />;
  return <Dashboard setPage={setPage} />;
}
export default function App() {
  return <AuthProvider><ResumeProvider><AppInner /></ResumeProvider></AuthProvider>;
}